import{_ as s,o as a,c as n,a4 as i}from"./chunks/framework.Cqne-ChA.js";const t="/assets/image2.DsUdLgKV.png",o="/assets/image3.CfvJg8FH.png",l="/assets/image4.L987JAzK.png",p="/assets/image5.Bm_SvtTF.png",r="/assets/image6.DZOri1Lb.png",c="/assets/image7.BNUzSRjO.png",d="/assets/image8.BqlUKHaM.png",u="/assets/image10.gfTGgfBe.png",h="/assets/image11.CcJOvMmk.png",m="/assets/image12.BC16NNeI.png",b="/assets/image13.BDXIhprr.png",g="/assets/image14.CWjj9DxD.png",v="/assets/image15.D4_Q3gR1.png",y="/assets/image16.7T4VjsiC.png",f="/assets/image17.BtAHVjvT.png",k="/assets/image18.DrMd-XYe.png",w="/assets/image19.CbHSpO4P.png",E=JSON.parse('{"title":"zopen community - Hands on Workshop","description":"","frontmatter":{},"headers":[],"relativePath":"workshop/workshop.md","filePath":"workshop/workshop.md","lastUpdated":1776850763000}'),_={name:"workshop/workshop.md"};function z(q,e,x,C,S,O){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="zopen-community-hands-on-workshop" tabindex="-1">zopen community - Hands on Workshop <a class="header-anchor" href="#zopen-community-hands-on-workshop" aria-label="Permalink to &quot;zopen community - Hands on Workshop&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A workstation with a terminal to access z/OS UNIX</li><li>Duration: 60 minutes</li><li>Userid and Password to login to the share machine (will be provided)</li></ul><h2 id="introduction-15-minutes" tabindex="-1">Introduction (15 minutes) <a class="header-anchor" href="#introduction-15-minutes" aria-label="Permalink to &quot;Introduction (15 minutes)&quot;">​</a></h2><p>Welcome to the zopen community Workshop, where we&#39;ll delve into how you can take advantage of open-source tools within the z/OS UNIX environment.</p><p>z/OS is renowned for its unwavering reliability, security, and speed. However, it&#39;s often challenged by the limited availability of readily available open-source software, compared to more common platforms such as Linux or Mac.</p><p>This is where the zopen community comes into play. Our primary mission is to enhance the open-source landscape on z/OS. With over 170 successfully ported open source projects, we&#39;re committed to making essential open-source tools readily available on z/OS. Importantly, we actively contribute our enhancements back to open-source communities to keep z/OS aligned with industry developments.</p><p>In today&#39;s session, we&#39;ll guide you through practical tasks like downloading and using the open source zopen package manager, installing core tools like Vim, Git, Make and Bash, and even introduce you to the process of porting an external tool (e.g., jq) using the zopen build command.</p><h2 id="module-1-accessing-z-os-unix-10-minutes" tabindex="-1">Module 1: Accessing z/OS UNIX (10 minutes) <a class="header-anchor" href="#module-1-accessing-z-os-unix-10-minutes" aria-label="Permalink to &quot;Module 1: Accessing z/OS UNIX (10 minutes)&quot;">​</a></h2><p>Make sure you have access to z/OS system, if not please reach out to:</p><ul><li>Igor Todorovski <a href="mailto:itodorov@ca.ibm.com" target="_blank" rel="noreferrer">itodorov@ca.ibm.com</a> or</li><li>Mike Fulton <a href="mailto:fultonm@ca.ibm.com" target="_blank" rel="noreferrer">fultonm@ca.ibm.com</a></li></ul><p>On getting access, log in to the z/OS UNIX system using SSH, you&#39;ll need to follow these steps:</p><ol><li><p>Open a terminal window. If you&#39;re on Windows, it&#39;s recommended that you use WSL - <a href="https://learn.microsoft.com/en-us/windows/wsl/install" target="_blank" rel="noreferrer">wsl installation steps</a>.</p><p>If you&#39;re on Mac, you can use Terminal or iTerm2 - <a href="https://iterm2.com/" target="_blank" rel="noreferrer">iterm2 installation steps</a>.</p></li><li><p>Logging in via SSH: You can use the provided userId and password to log into a z/OS system.</p><ul><li>Here&#39;s an example of how to do it: <ul><li>ssh <a href="mailto:yoursid@hostname.com" target="_blank" rel="noreferrer">yoursid@hostname.com</a></li><li>NOTE: Replace yourid with the z/OS userid provided and hostname with z/OS host name</li></ul></li></ul></li></ol><h2 id="module-2-downloading-and-installing-zopen-community-meta-framework-10-mins" tabindex="-1">Module 2: Downloading and Installing zopen community Meta Framework (10 mins) <a class="header-anchor" href="#module-2-downloading-and-installing-zopen-community-meta-framework-10-mins" aria-label="Permalink to &quot;Module 2: Downloading and Installing zopen community Meta Framework (10 mins)&quot;">​</a></h2><h3 id="video-guide-optional" tabindex="-1">Video guide: (Optional) <a class="header-anchor" href="#video-guide-optional" aria-label="Permalink to &quot;Video guide: (Optional)&quot;">​</a></h3><ul><li>There is a video guide provided here. It can be used as reference as you work through the workshop.</li></ul><video height="1080" controls><source src="https://github.com/zopencommunity/collateral/raw/main/ZOSOpenToolsIntroV2-cropped.mp4" type="video/mp4"> Your browser does not support the video tag. </video><h2 id="module-3-setting-up-your-z-os-environment" tabindex="-1">Module 3: Setting up your z/OS environment <a class="header-anchor" href="#module-3-setting-up-your-z-os-environment" aria-label="Permalink to &quot;Module 3: Setting up your z/OS environment&quot;">​</a></h2><ul><li>z/OS Open Source tools leverage z/OS Enhanced ASCII support. This support enables automatic conversion between codepages for tagged files. To take advantage of this support, you need to set the following environment variables on z/OS UNIX:</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export _BPXK_AUTOCVT=ON</span></span>
<span class="line"><span>export _CEE_RUNOPTS=&quot;$_CEE_RUNOPTS FILETAG(AUTOCVT,AUTOTAG) POSIX(ON)&quot;</span></span>
<span class="line"><span>export _TAG_REDIR_ERR=txt</span></span>
<span class="line"><span>export _TAG_REDIR_IN=txt</span></span>
<span class="line"><span>export _TAG_REDIR_OUT=txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>We recommend adding these environment variables to your .profile or .bashrc startup script.</p><h3 id="required-tools" tabindex="-1">Required Tools <a class="header-anchor" href="#required-tools" aria-label="Permalink to &quot;Required Tools&quot;">​</a></h3><ul><li><p>If you want to contribute and improve the z/OS Open Source Tools</p><pre><code>-	You will need the IBM C/C++ compiler on your system. There are two options:
	1. XL CLang
</code></pre><ul><li><p>The default compiler is xlclang. You can download it as a web deliverable add-on feature to your XL C/C++ compiler <a href="https://www.ibm.com/servers/resourcelink/svc00100.nsf/pages/xlCC++V241ForZOsV24" target="_blank" rel="noreferrer">here</a>.</p><pre><code>2. Clang
</code></pre></li><li><p>You can install and manage <em>C/C++ for Open Enterprise Languages on z/OS</em> using <em>RedHat OpenShift Container Platform</em> and <em>IBM Z and Cloud Modernization Stack</em></p></li><li><p>Alternatively, you can download the pax edition from IBM <a href="https://epwt-www.mybluemix.net/software/support/trial/cst/programwebsite.wss?siteId=1803" target="_blank" rel="noreferrer">here</a>.</p></li></ul><ol start="3"><li>If you are building Go projects, you will need the IBM Open Enterprise SDK for Go compiler installed. You can obtain it <a href="https://www.ibm.com/products/open-enterprise-sdk-go-zos" target="_blank" rel="noreferrer">here</a>.</li></ol></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export PATH=&quot;&lt;path_to_compiler&gt;:$PATH&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="installing-the-zopen-meta-framework" tabindex="-1">Installing the zopen meta framework <a class="header-anchor" href="#installing-the-zopen-meta-framework" aria-label="Permalink to &quot;Installing the zopen meta framework&quot;">​</a></h3><ul><li>Create a temp_zopen dir:</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mkdir -p \${HOME}/temp_zopen</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><p>Download the latest pax file from <a href="https://github.com/zopencommunity/meta/releases" target="_blank" rel="noreferrer"> meta releases </a></p></li><li><p>Copy the pax file from the download directory to <code>\${HOME}/temp_zopen/</code> using command:</p></li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>	cp &lt;download_dir&gt;/&lt;meta_pax_file_name&gt; \${HOME}/temp_zopen/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><p><code>cd</code> into <code>\${HOME}/temp_zopen/</code>, the directory you transferred the pax.Z file to</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd \${HOME}/temp_zopen/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Extract the pax file using command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pax -rf meta-0.8.1.pax.Z # extract the pax</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>After this step, you may delete the <code>meta-0.8.1.pax.Z</code> file</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rm meta-0.8.1.pax.Z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Now you can install zopen meta framework using commands:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd meta-0.8.1</span></span>
<span class="line"><span>. ./.env</span></span>
<span class="line"><span>zopen init # Follow the instructions</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p>Provide the zopen root directory as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> $HOME/zopen_tools</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>After completion, source the zopen-config, using the dot (.) operator, as instructed in the <strong>last line</strong> from the <code>zopen init</code> output.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> . $HOME/zopen_tools/etc/zopen-config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><h2 id="module-4-installing-core-tools-10-minutes" tabindex="-1">Module 4: Installing core tools (10 minutes) <a class="header-anchor" href="#module-4-installing-core-tools-10-minutes" aria-label="Permalink to &quot;Module 4: Installing core tools (10 minutes)&quot;">​</a></h2><h3 id="use-the-zopen-framework-to-list-available-tools" tabindex="-1">Use the zopen framework to list available tools <a class="header-anchor" href="#use-the-zopen-framework-to-list-available-tools" aria-label="Permalink to &quot;Use the zopen framework to list available tools&quot;">​</a></h3><ul><li><code>zopen list</code> # list the available tools, this will list 100+ tools available under zopen community</li><li><code>zopen list -–installed</code> # list of installed tools</li></ul><h3 id="install-your-favourite-tools" tabindex="-1">Install your favourite tools <a class="header-anchor" href="#install-your-favourite-tools" aria-label="Permalink to &quot;Install your favourite tools&quot;">​</a></h3><ul><li><p>Install vim: (Editor)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install vim -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Install git: (Source control tool)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen install git -y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You will notice that it will install git and its runtime dependencies, bash, ncurses, and others.</p></li></ul><h2 id="module-5-using-your-newly-installed-zopen-community-15-minutes" tabindex="-1">Module 5: Using your newly installed zopen community (15 minutes) <a class="header-anchor" href="#module-5-using-your-newly-installed-zopen-community-15-minutes" aria-label="Permalink to &quot;Module 5: Using your newly installed zopen community (15 minutes)&quot;">​</a></h2><h3 id="using-bash-on-z-os" tabindex="-1">Using Bash on z/OS <a class="header-anchor" href="#using-bash-on-z-os" aria-label="Permalink to &quot;Using Bash on z/OS&quot;">​</a></h3><ol><li><p>Bash was installed via Git as it is a dependency for Git. It&#39;s recommended that you use Bash on z/OS for the following reasons:</p><ul><li><p>Tab Completion: Bash offers tab completion for efficient command and filename typing, saving time and reducing errors.</p></li><li><p>Scripting Power: Bash serves as a robust scripting language capable of automating complex tasks, enabling advanced operations with variables, loops, and conditions.</p></li><li><p>Compatibility: Bash is compatible with the Bourne shell, allowing seamless migration of existing scripts without the need for extensive rewriting.</p></li></ul></li><li><p>To invoke bash, type:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You have now entered the bash shell.</p></li><li><p>Type in <code>ls &lt;tab&gt;</code>will auto-complete and list all files/directories in your current working directory.</p></li></ol><h3 id="using-git-on-z-os" tabindex="-1">Using Git on z/OS <a class="header-anchor" href="#using-git-on-z-os" aria-label="Permalink to &quot;Using Git on z/OS&quot;">​</a></h3><ol><li><p>Skip the steps below if you have a github.com userID, otherwise follow the below steps.</p><p>a. Login to <a href="https://github.com/" target="_blank" rel="noreferrer">github.com</a> and click on Sign up, towards the top right corner.</p><p><img src="`+t+'" alt=""></p><p>b. Provide the details related to preferred email id.</p><p><img src="'+o+'" alt=""></p><p>c. Enter the preferred password, username, verify your account and click on create account.</p><p><img src="'+l+'" alt=""></p><p><img src="'+p+'" alt=""></p><p>d. Further provide your details and click continue:</p><p><img src="'+r+'" alt=""></p><p>e. Select the first free option, scroll down and click on continue for free:</p><p><img src="'+c+'" alt=""></p><p>f. Then you will land on your home page as shown below:</p><p><img src="'+d+`" alt=""></p></li></ol><h2 id="module-6-building-existing-zopen-community-20-mins" tabindex="-1">Module 6: Building existing zopen community (20 mins) <a class="header-anchor" href="#module-6-building-existing-zopen-community-20-mins" aria-label="Permalink to &quot;Module 6: Building existing zopen community (20 mins)&quot;">​</a></h2><p>Now that you&#39;ve gained some experience with using the zopen community, let&#39;s attempt to build an existing open source project, Git.</p><ol><li><p>Create a directory dev under $HOME/temp_zopen:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> mkdir -p $HOME/temp_zopen/dev</span></span>
<span class="line"><span> cd $HOME/temp_zopen/dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p>Clone the <a href="https://github.com/zopencommunity/gitport" target="_blank" rel="noreferrer">gitport</a> repository and change to the gitport local workspace as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/zopencommunity/gitport</span></span>
<span class="line"><span>cd gitport</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p>You will notice that there are several files, and most notably, the <code>buildenv</code> configuration. This file instructs <code>zopen build</code> on how to build the <code>git</code> tool.</p><p>For more details on the <code>buildenv</code> configuration, visit <a href="https://zopencommunity.github.io/meta/#/Guides/Porting" target="_blank" rel="noreferrer">https://zopencommunity.github.io/meta/#/Guides/Porting</a>.</p><p>(As mentioned in Module 3, ensure the path to the compiler is set.)</p></li></ol><p>Now, let&#39;s attempt to build gitport: <code> zopen build –vv </code></p><pre><code>It completes build and installation as shown below:

![](./media/image9.png)

After approximately 10 minutes for \`git\` build, test and install.
</code></pre><h2 id="module-7-porting-a-new-open-source-tool-with-zopen-community-20-mins" tabindex="-1">Module 7: Porting a new open source tool with zopen community (20 mins) <a class="header-anchor" href="#module-7-porting-a-new-open-source-tool-with-zopen-community-20-mins" aria-label="Permalink to &quot;Module 7: Porting a new open source tool with zopen community (20 mins)&quot;">​</a></h2><p>Now that you understand the build process, let&#39;s attempt to port an open source tool to z/OS by leveraging <code>zopen generate</code>.</p><h3 id="prerequisites-setting-up-ssh-on-z-os" tabindex="-1"><strong>Prerequisites : Setting up ssh on z/OS</strong> <a class="header-anchor" href="#prerequisites-setting-up-ssh-on-z-os" aria-label="Permalink to &quot;**Prerequisites : Setting up ssh on z/OS**&quot;">​</a></h3><p>For this step, you will be contributing your changes to github. It is recommended that you setup an SSH key pair to avoid logging in everytime you access the remote repository.</p><p>Here are the basic steps to create an SSH key pair on z/OS:</p><ol><li><p>Open a terminal window.</p></li><li><p>Generate the SSH Key Pair: To create your SSH key pair, enter the following command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh-keygen</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>You&#39;ll be prompted to specify a file name for your key pair. Provide &quot;/u/&lt;userid&gt;/.ssh/id_rsa &quot;as input, but you have the option to choose a different name if you prefer.</p></li><li><p>Set a Passphrase (Optional but Recommended): You will also be given the option to set a passphrase for your key pair. While this step is optional, it&#39;s highly recommended as it adds an additional layer of security to your SSH connection. If you choose to set a passphrase, you&#39;ll need to enter it during SSH authentication.</p></li><li><p>Example:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Enter file in which to save the key &quot;$HOME/.ssh/id\\_rsa): &quot;$HOME/.ssh/id_rsa&quot;</span></span>
<span class="line"><span>Enter passphrase (empty for no passphrase):</span></span>
<span class="line"><span>Enter same passphrase again:</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p>The key pair will be generated and saved in the .ssh directory within your home directory. The private key will be saved as id_rsa (or the name you specified), and the corresponding public key will be saved as id_rsa.pub.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Example output:</span></span>
<span class="line"><span>Your identification has been saved in &quot;$HOME/.ssh/id_rsa.</span></span>
<span class="line"><span>Your public key has been saved in &quot;$HOME/.ssh/id_rsa.pub.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></li><li><p>Go to you github.com page and on top right corner click on you profile icon to get below drop down:</p><p><img src="`+u+'" alt="A screenshot of a computer Description automatically generated"></p></li><li><p>Click on Settings and select SSH and GPG Keys on left:</p><p><img src="'+h+'" alt="A screenshot of a phone Description automatically generated"></p><p><img src="'+m+'" alt="A screenshot of a computer Description automatically generated"></p></li><li><p>Click on New SSH Key button:</p><p><img src="'+b+'" alt="A white background with blue text Description automatically generated"></p></li><li><p>Copy the id_rsa.pub key generated above and paste it in the key field and click add key:</p><p><img src="'+g+`" alt="A screenshot of a computer Description automatically generated"></p><p>Please note that the precise commands and prompts may vary slightly depending on your operating system and the version of SSH you are using.</p></li></ol><p>We will choose <a href="https://stedolan.github.io/jq/" target="_blank" rel="noreferrer">jq</a>, a lightweight and flexible json parser.</p><ol><li><p>Begin first by generating a port template project by entering the following command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen generate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><code>zopen generate</code> will ask you a series of questions. Answer them as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Generate a zopen project...</span></span>
<span class="line"><span>* What is the project name?</span></span>
<span class="line"><span>	jq</span></span>
<span class="line"><span>* Provided a description of the project:</span></span>
<span class="line"><span>	A jq parser</span></span>
<span class="line"><span>* Valid categories: security development language ai core editor source_control networking</span></span>
<span class="line"><span>* What categories does the project fit under? (delimit with a space):</span></span>
<span class="line"><span>  	development</span></span>
<span class="line"><span>* Provide the community license to use for jq&#39;s patches: (select from key agpl-3.0 apache-2.0 bsd-2-clause bsd-3-clause bsl-1.0 cc0-1.0 epl-2.0 gpl-2.0 gpl-3.0 lgpl-2.1 mit mpl-2.0 unlicense)</span></span>
<span class="line"><span>  	unlicense</span></span>
<span class="line"><span>* Enter jq&#39;s stable release source url: (Specify a Git or Tarball URL. If none, press enter)</span></span>
<span class="line"><span>* Enter jq&#39;s zopen community build dependencies for the stable build: (Enter multiple dependencies using spaces. E.g: zoslib make grep)</span></span>
<span class="line"><span>* Enter jq&#39;s dev-line source url: (Specify a Git or Tarball URL. If none, press enter)</span></span>
<span class="line"><span>  	git@github.com:stedolan/jq.git</span></span>
<span class="line"><span>* Enter jq&#39;s zopen community build dependencies for the dev build: (Enter multiple dependencies using spaces. E.g: zoslib make grep)</span></span>
<span class="line"><span>	git make autoconf</span></span>
<span class="line"><span>* Enter the default build line: (stable or dev)</span></span>
<span class="line"><span>	dev</span></span>
<span class="line"><span>* Enter jq&#39;s zopen community runtime dependencies: (example: bash)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Generating jqport zopen project</span></span>
<span class="line"><span>jqport/buildenv created</span></span>
<span class="line"><span>jqport/README.md created</span></span>
<span class="line"><span>jqport/.gitignore created</span></span>
<span class="line"><span>jq project is ready! jqport/</span></span>
<span class="line"><span>Create patches under the jqport/patches directory</span></span>
<span class="line"><span>Run zopen build to build jqport</span></span>
<span class="line"><span>Contact Igor Todorovski (itodorov@ca.ibm.com) to create https://github.com/zopencommunity/jqport.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br></div></div></li><li><p>Change your current directory to the jqport directory:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd jqport</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You will notice several files:</p><ul><li>README.md - A description of the project</li><li>buildenv - The zopen configuration file that drives the build, testing, and installation of the project.</li><li>cicd-dev.groovy - The CI/CD configuration file used in the Jenkins pipeline.</li></ul><p>For more information, please visit the <a href="https://github.com/zopencommunity/meta" target="_blank" rel="noreferrer">zopen build README</a></p><p>Note: <code>zopen build</code> supports projects based in github repositories or tarball locations. Since autoconf/automake are not currently 100% functional on z/OS, we typically choose the tarball location because it contains a <code>configure</code> script pre-packaged. Let&#39;s go ahead and do this for <code>jq</code>.</p><p>In the <code>buildenv</code> file, you&#39;ll notice the following contents:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export ZOPEN_DEV_URL=&quot;git@github.com:stedolan/jq.git&quot;</span></span>
<span class="line"><span>export ZOPEN_DEV_DEPS=&quot;git make autoconf&quot;</span></span>
<span class="line"><span>export ZOPEN_CATEGORIES=&quot;development&quot;</span></span>
<span class="line"><span>export ZOPEN_BUILD_LINE=&quot;DEV&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>zopen_check_results()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	dir=&quot;$1&quot;</span></span>
<span class="line"><span>	pfx=&quot;$2&quot;</span></span>
<span class="line"><span>	chk=&quot;$1/$2_check.log&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	# Echo the following information to gauge build health</span></span>
<span class="line"><span>	echo &quot;actualFailures:0&quot;</span></span>
<span class="line"><span>	echo &quot;totalTests:1&quot;</span></span>
<span class="line"><span>	echo &quot;expectedFailures:0&quot;</span></span>
<span class="line"><span>	echo &quot;expectedTotalTests:1&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>zopen_get_version()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	# Modify to echo the version of your tool/library</span></span>
<span class="line"><span>	# Rather than hardcoding the version, obtain the version by running the tool/library</span></span>
<span class="line"><span>	echo &quot;1.0.0&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p>ZOPEN_STABLE_DEPS: are used to identify the non-standard zopen community dependencies needed to build the project.</p><p><code>zopen_append_to_env()</code> can be used to add additional environment variables outside of the normal environment variables. (e.g. PATH, LIBPATH, MANPATH)</p><p>Similarly, <code>zopen_append_to_zoslib_env()</code> can be used to set program specific environment variables. It accepts the following format: envar|action|value Where envar is the environment variable, action is either set, unset, or prepend, and value is the environment variable value. The string <code>PROJECT_HOME</code> represents a special value and is replaced with the root path of the project&quot;</p><p>To help gauge the build quality of the port, a <code>zopen_check_results()</code> function needs to be provided inside the buildenv. This function should process the test results and emit a report of the failures, total number of tests, expected number of failures and expected number of tests to stdout as in the following format:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>actualFailures:&lt;numberoffailures&gt;</span></span>
<span class="line"><span>totalTests:&lt;totalnumberoftests&gt;</span></span>
<span class="line"><span>expectedFailures:&lt;expectednumberoffailures&gt;</span></span>
<span class="line"><span>expectedTotalTests:&lt;expectednumberoftests&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The build will fail to proceed to the install step if totalTests is less than expectedTotalTests or actualFailures is greater than expectedFailures.</p></li><li><p>Here is an example implementation of zopen_check_results():</p><pre><code>zopen_check_results()
{
	chk=&quot;$1/$2_check.log&quot;
	failures=$(grep &quot;.* Test.*in .* Categories Failed&quot; \${chk} | cut -f1 -d&#39; &#39;)
	totalTests=$(grep &quot;.* Test.*in .* Categories Failed&quot; \${chk} | cut -f5 -d&#39; &#39;)
	cat &lt;&lt;ZZ
	actualFailures:$failures
	totalTests:$totalTests
	expectedFailures:0
	expectedTotalTests:1
	ZZ
}
</code></pre><p>Next, we can go ahead and test our build. Run the following:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zopen build -v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The <code>-v</code> option above specifies verbose output.</p></li><li><p>We get the following error:</p><p><img src="`+v+`" alt="A screenshot of a computer screen Description automatically generated"></p><p>We need the following patch for jq to build on z/OS: (to handle all the interlibrary dependencies passed with no checks)</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>openedition)</span></span>
<span class="line"><span>lt_cv_deplibs_check_method=pass_all</span></span>
<span class="line"><span>;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Once finished, you will notice that your project was built and installed under <code>&lt;zopen_root_fs&gt;/usr/local/zopen/jq/jq</code>.</p><p><strong>Create patches:</strong></p><ol><li><p>Navigate to jqport directory.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd jqport/jq-1.6</span></span>
<span class="line"><span>git status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p>You will notice that the file configure is modified.</p></li><li><p>Now create the patch using following command:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git diff configure &gt; ../patches/configure.patch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>You can commit this change back to the repo by using the installed git.</p></li><li><p>Create a fork of jqport.</p><ul><li>Click on drop down next to fork button:</li></ul><p><img src="`+y+'" alt="A screenshot of a computer Description automatically generated"></p><ul><li><p>Click on Create a new fork from drop down:</p><p><img src="'+f+'" alt="A screenshot of a computer Description automatically generated"></p></li><li><p>Fill Data and click on Create fork button:</p><p><img src="'+k+'" alt="A screenshot of a computer Description automatically generated"></p></li><li><p>You can now use the URL from the &quot;code&quot; drop down option:</p><p><img src="'+w+`" alt="A screenshot of a computer Description automatically generated"></p></li></ul></li><li><p>Now, let&#39;s use Git to clone a remote repository:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone git@github.com:&lt;userName&gt;/jqport.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>This will clone the remote repository, jqport, to your local z/OS UNIX system under the directory <code>jqport</code>. Change to the jqport directory:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd jqport</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Check the commit log history:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Scroll up or down using the arrow keys on your keyboard</p></li><li><p>Now let&#39;s make a change. We will use <code>vim</code> to edit a file locally and make a change. vim the README.md file:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vim README.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Now edit the file by pressing i to enter insert mode:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Now start typing text. Once you are done, press the <code>escape</code> key. You have now exited insert mode. To save the file, press:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:wq</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Now, let&#39;s use git to check what&#39;s different:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git diff</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You should see your changes reflected in the view.</p></li><li><p>Commit your changes.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git add README.md</span></span>
<span class="line"><span>git commit -a README.md -m &quot;My changes&quot;</span></span>
<span class="line"><span>git push</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Once you&#39;ve committed your change, typically the next step is to push your changes to remote.</p></li></ol></li></ol><h2 id="how-to-get-involved" tabindex="-1">How to get involved? <a class="header-anchor" href="#how-to-get-involved" aria-label="Permalink to &quot;How to get involved?&quot;">​</a></h2><p>Become a part of the z/OS Open Source Technology community either as a <strong>developer</strong> or a <strong>consumer</strong>.</p><ul><li>As a developer: <ul><li>if you want to work on new tools, visit pages <a href="https://github.com/orgs/zopencommunity/discussions/23" target="_blank" rel="noreferrer">1</a> and <a href="https://github.com/orgs/zopencommunity/discussions/433" target="_blank" rel="noreferrer">2</a>, choose a tool to begin the development activity, as outlined <a href="https://zopencommunity.github.io/meta/#/Guides/developing" target="_blank" rel="noreferrer">here</a>.</li><li>Alternatively, if you prefer working on existing tools, you can select one of the help-wanted issues from <a href="https://github.com/search?q=user%3Azopencommunity+repo%3Ahttps%3A%2F%2Fgithub.com%2Fzopencommunity+label%3A%22help+wanted%22+state%3Aopen&amp;type=issues&amp;ref=advsearch&amp;state=open" target="_blank" rel="noreferrer">here</a>.</li></ul></li><li>If you&#39;d like to contribute as a consumer of these tools, you can start by visiting this <a href="https://zopencommunity.github.io/meta/#/Guides/QuickStart" target="_blank" rel="noreferrer">link</a></li></ul><h2 id="what-s-next-5-minutes" tabindex="-1">What&#39;s next (5 minutes) <a class="header-anchor" href="#what-s-next-5-minutes" aria-label="Permalink to &quot;What&#39;s next (5 minutes)&quot;">​</a></h2><p>If you&#39;re interested in participating further, we hold regular meetings to explore the latest advancements in zopen community via the <a href="https://github.com/orgs/zopencommunity/discussions/categories/guild" target="_blank" rel="noreferrer">z/OS Open Source Guild Meetings</a></p><p>We&#39;re dedicated to building a community of z/OS enthusiasts who collaborate and share their work on GitHub through the &quot;z/OS Open Source Guild&quot;. Feel free to also participate in our <a href="https://github.com/orgs/zopencommunity/discussions" target="_blank" rel="noreferrer">discussions</a>. For a list of existing issues and how you can get involved, visit <a href="https://github.com/orgs/zopencommunity/issues" target="_blank" rel="noreferrer">issues</a>.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://github.com/orgs/zopencommunity" target="_blank" rel="noreferrer">Github repository</a></li><li><a href="https://zopencommunity.github.io/meta" target="_blank" rel="noreferrer">Documentation</a></li><li><a href="https://zopencommunity.github.io/meta/#/Guides/QuickStart?id=getting-started-video" target="_blank" rel="noreferrer">Video demo</a></li><li><a href="https://github.com/orgs/zopencommunity/discussions" target="_blank" rel="noreferrer">Discussions</a></li><li><a href="https://discord.gg/Cgwf6F6dqj" target="_blank" rel="noreferrer">Discord channel</a></li><li><a href="https://github.com/orgs/zopencommunity/discussions/categories/guild" target="_blank" rel="noreferrer">Guild meeting session</a></li></ul>`,61)])])}const I=s(_,[["render",z]]);export{E as __pageData,I as default};
